import json
from web3 import Web3

# Initialize the Web3 instance
w3 = Web3(Web3.HTTPProvider('http://localhost:8545'))

# Define a function to verify Ethereum wallet signatures
def verify_signature(message, signature):
    # Recover the address from the signed message
    recovered_address = w3.eth.account.recoverHash(message, signature)

    # Verify if the recovered address is the same as the user's wallet address
    if recovered_address == '0x...':  # Replace with user's wallet address
        return True
    else:
        return False

# Define a function to accept signed messages from users and authenticate based on recovered address
def accept_message(signed_message):
    # Extract the message and signature from the signed message
    message = json.loads(signed_message)['message']
    signature = json.loads(signed_message)['signature']

    # Verify the Ethereum wallet signature
    if verify_signature(message, signature):
        return True
    else:
        return False